<template>
  <div class="header">
    <div class="header__buttons">
      <button
        class="btn"
        @click="changeLanguage"
        :aria-label="isSpanish ? 'Switch to English' : 'Cambiar a Español'"
      >
        <i class="fa-solid fa-language"></i>
      </button>
      <button
        class="btn"
        @click="print"
        :aria-label="isSpanish ? 'Imprimir CV' : 'Print CV'"
      >
        <i class="fa-solid fa-print"></i>
      </button>
    </div>

    <div class="header__name">
      <h1>
        Juan David
        <span class="name-bold">Nuñez Aguilar</span>
      </h1>
    </div>

    <div class="header__rule">
      <span class="header__rule__line"></span>
      <span class="header__rule__gem">◆</span>
      <span class="header__rule__line"></span>
    </div>

    <h2 class="header__name__job">{{ job }}</h2>
  </div>
</template>

<script lang="ts">
import { defineComponent } from "vue";

export default defineComponent({
  props: {
    isSpanish: {
      type: Boolean,
      required: true,
    },
  },
  methods: {
    changeLanguage() {
      this.$emit("triggerLanguage");
    },
    print() {
      window.print();
    },
  },
  computed: {
    job: function (): string {
      return this.isSpanish ? "Desarrollador front end" : "Front end developer";
    },
  },
});
</script>
